    println!("{:?}", remove_duplicates(vec![1, 2, 2, 3, 1, 4]));
}

solution.code:
use std::collections::HashSet;

fn remove_duplicates(nums: Vec<i32>) -> Vec<i32> {
    let mut seen = HashSet::new();
    let mut result = Vec::new();
    for n in nums {
        if seen.insert(n) {
            result.push(n);
        }
    }
    result
}

fn main() {
    println!("{:?}", remove_duplicates(vec![1, 2, 2, 3, 1, 4]));
}

