challenges.starterCode:
fn rotate_right(items: &[i32], k: usize) -> Vec<i32> {
    // Your code here
    Vec::new()
}

solution.code:
fn rotate_right(items: &[i32], k: usize) -> Vec<i32> {
    if items.is_empty() {
        return Vec::new();
    }
    let shift = k % items.len();
    let mut out = Vec::with_capacity(items.len());
    out.extend_from_slice(&items[items.len() - shift..]);
    out.extend_from_slice(&items[..items.len() - shift]);
    out
}

steps.code:
fn rotate_right(items: &[i32], k: usize) -> Vec<i32> {
    if items.is_empty() {
        return Vec::new();
    }
    let shift = k % items.len();
