fn min_max<T: PartialOrd + Clone>(items: &[T]) -> Option<(T, T)> {
    let first = items.first()?.clone();
    let mut min = first.clone();
    let mut max = first;
    for item in items.iter().skip(1) {
        if *item < min {
            min = item.clone();
        }
        if *item > max {
            max = item.clone();
        }
    }
    Some((min, max))
}

