fn lis_length(nums: &[i32]) -> usize {
    if nums.is_empty() {
        return 0;
    }
    let n = nums.len();
    let mut dp = vec![1usize; n];
    for i in 1..n {
        for j in 0..i {
            if nums[j] < nums[i] {
                dp[i] = dp[i].max(dp[j] + 1);
            }
        }
    }
    *dp.iter().max().unwrap()
}

