use std::collections::VecDeque;

fn bfs_shortest(adj: &Vec<Vec<usize>>, start: usize, end: usize) -> Option<usize> {
    if start == end {
        return Some(0);
    }
    let n = adj.len();
    if start >= n || end >= n {
        return None;
    }
    let mut visited = vec![false; n];
    let mut queue = VecDeque::new();
    visited[start] = true;
    queue.push_back((start, 0usize));
    while let Some((node, dist)) = queue.pop_front() {
        for &neighbor in &adj[node] {
            if neighbor == end {
                return Some(dist + 1);
            }
            if !visited[neighbor] {
                visited[neighbor] = true;
                queue.push_back((neighbor, dist + 1));
            }
        }
    }
    None
}

fn main() {
    let mut adj = vec![vec![]; 6];
    adj[0].push(1);
    adj[0].push(2);
    adj[1].push(3);
    adj[2].push(3);
    adj[3].push(4);
    adj[4].push(5);
    adj[2].push(5);
    println!("{:?}", bfs_shortest(&adj, 0, 5));
    println!("{:?}", bfs_shortest(&adj, 0, 6));
}

