solution.code:
fn matrix_chain_order(dims: &[usize]) -> usize {
    let n = dims.len() - 1;
    if n <= 1 {
        return 0;
    }
    let mut m = vec![vec![0usize; n]; n];
    for chain_len in 2..=n {
        for i in 0..=(n - chain_len) {
            let j = i + chain_len - 1;
            m[i][j] = usize::MAX;
            for k in i..j {
                let cost = m[i][k] + m[k + 1][j] + dims[i] * dims[k + 1] * dims[j + 1];
                if cost < m[i][j] {
                    m[i][j] = cost;
                }
            }
        }
    }
    m[0][n - 1]
}

fn main() {
    println!("{}", matrix_chain_order(&[10, 30, 5, 60]));
    println!("{}", matrix_chain_order(&[40, 20, 30, 10, 30]));
}

