use std::collections::BinaryHeap;
use std::cmp::Reverse;

fn dijkstra(adj: &Vec<Vec<(usize, u32)>>, start: usize, end: usize) -> Option<u32> {
    let n = adj.len();
    if end >= n {
        return None;
    }
    let mut dist = vec![u32::MAX; n];
    let mut heap = BinaryHeap::new();
    dist[start] = 0;
    heap.push(Reverse((0u32, start)));
    while let Some(Reverse((d, u))) = heap.pop() {
        if u == end {
            return Some(d);
        }
        if d > dist[u] {
            continue;
        }
        for &(v, w) in &adj[u] {
            let new_dist = d + w;
            if new_dist < dist[v] {
                dist[v] = new_dist;
                heap.push(Reverse((new_dist, v)));
            }
        }
    }
    if dist[end] == u32::MAX {
        None
    } else {
        Some(dist[end])
    }
}

fn main() {
    let mut adj = vec![vec![]; 4];
    adj[0].push((1, 4));
    adj[0].push((2, 1));
    adj[2].push((1, 2));
    adj[1].push((3, 1));
    adj[2].push((3, 5));
    println!("{:?}", dijkstra(&adj, 0, 3));
    println!("{:?}", dijkstra(&adj, 0, 4));
}

