    let kind1 = match &result1 {
        Cow::Borrowed(_) => "borrowed",
        Cow::Owned(_) => "owned",
    };
    println!("{} ({})", result1, kind1);

    let result2 = ensure_prefix("say: hi", "say: ");
    let kind2 = match &result2 {
