use std::borrow::Cow;

fn ensure_prefix<'a>(s: &'a str, prefix: &str) -> Cow<'a, str> {
    if s.starts_with(prefix) {
        Cow::Borrowed(s)
    } else {
        Cow::Owned(format!("{}{}", prefix, s))
    }
}

fn main() {
    let result1 = ensure_prefix("hello", "say: ");
    let kind1 = match &result1 {
        Cow::Borrowed(_) => "borrowed",
        Cow::Owned(_) => "owned",
    };
    println!("{} ({})", result1, kind1);

    let result2 = ensure_prefix("say: hi", "say: ");
    let kind2 = match &result2 {
        Cow::Borrowed(_) => "borrowed",
        Cow::Owned(_) => "owned",
    };
    println!("{} ({})", result2, kind2);
}

