solution.code:
use std::fmt;
use std::error::Error;

#[derive(Debug)]
enum ParseError {
    Empty,
    InvalidNumber(String),
    TooManyParts,
}

impl fmt::Display for ParseError {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        match self {
            ParseError::Empty => write!(f, "Empty"),
            ParseError::InvalidNumber(s) => write!(f, "InvalidNumber(\"{}\")", s),
            ParseError::TooManyParts => write!(f, "TooManyParts"),
        }
    }
}

impl Error for ParseError {}

fn parse_single_number(s: &str) -> Result<i32, ParseError> {
    let trimmed = s.trim();
    if trimmed.is_empty() {
        return Err(ParseError::Empty);
    }
    trimmed.parse::<i32>().map_err(|_| ParseError::InvalidNumber(trimmed.to_string()))
}

fn main() {
    println!("{:?}", parse_single_number("42"));
    println!("{:?}", parse_single_number(""));
    println!("{:?}", parse_single_number("abc"));
