use std::collections::HashMap;

fn make_memoized_fib() -> impl FnMut(u64) -> (u64, usize) {
    let mut cache: HashMap<u64, u64> = HashMap::new();

    move |n: u64| -> (u64, usize) {
        if let Some(&result) = cache.get(&n) {
            return (result, cache.len());
        }

        let result = if n <= 1 {
            n
        } else {
            let mut a = 0u64;
            let mut b = 1u64;
            for _ in 2..=n {
                let temp = a + b;
                a = b;
                b = temp;
            }
            b
        };

        cache.insert(n, result);
        (result, cache.len())
    }
}

fn main() {
    let mut fib = make_memoized_fib();
    let (result, _) = fib(10);
    println!("fib(10) = {}", result);
    let (result, size) = fib(10);
    println!("fib(10) = {} (cached)", result);
    println!("Cache size: {}", size);
}

