use std::cell::{RefCell, Ref};

struct Lazy<T, F: FnOnce() -> T> {
    value: RefCell<Option<T>>,
    init: RefCell<Option<F>>,
}

impl<T, F: FnOnce() -> T> Lazy<T, F> {
    fn new(f: F) -> Self {
        Lazy {
            value: RefCell::new(None),
            init: RefCell::new(Some(f)),
        }
    }

    fn get(&self) -> Ref<T> {
        if self.value.borrow().is_none() {
            let f = self.init.borrow_mut().take().unwrap();
            *self.value.borrow_mut() = Some(f());
        }
        Ref::map(self.value.borrow(), |opt| opt.as_ref().unwrap())
    }
}

fn main() {
    let lazy = Lazy::new(|| {
        println!("Computing expensive value...");
        42
    });

    println!("First access: {}", *lazy.get());
    println!("Second access: {}", *lazy.get());
}

