struct BothEnds<T> {
    data: Vec<T>,
    front: usize,
    back: usize,
}

impl<T: Clone> BothEnds<T> {
    fn new(data: Vec<T>) -> Self {
        let len = data.len();
        BothEnds { data, front: 0, back: len }
    }
}

impl<T: Clone> Iterator for BothEnds<T> {
    type Item = T;

    fn next(&mut self) -> Option<Self::Item> {
        if self.front < self.back {
            let item = self.data[self.front].clone();
            self.front += 1;
            Some(item)
        } else {
            None
        }
    }
}

impl<T: Clone> DoubleEndedIterator for BothEnds<T> {
    fn next_back(&mut self) -> Option<Self::Item> {
        if self.front < self.back {
            self.back -= 1;
            Some(self.data[self.back].clone())
        } else {
            None
        }
    }
}

fn main() {
    let mut iter = BothEnds::new(vec![1, 2, 3, 4]);
    println!("Front: {}, Back: {}", iter.next().unwrap(), iter.next_back().unwrap());
    println!("Front: {}, Back: {}", iter.next().unwrap(), iter.next_back().unwrap());
}

