use std::ops::{BitOr, BitAnd, Not};

#[derive(Debug, Clone, Copy)]
struct Permissions(u8);

impl Permissions {
    const READ: Permissions = Permissions(1);
    const WRITE: Permissions = Permissions(2);
    const EXECUTE: Permissions = Permissions(4);

    fn contains(&self, other: Permissions) -> bool {
        (self.0 & other.0) == other.0
    }
}

impl BitOr for Permissions {
    type Output = Self;
    fn bitor(self, rhs: Self) -> Self::Output {
        Permissions(self.0 | rhs.0)
    }
}

impl BitAnd for Permissions {
    type Output = Self;
    fn bitand(self, rhs: Self) -> Self::Output {
        Permissions(self.0 & rhs.0)
    }
}

impl Not for Permissions {
    type Output = Self;
    fn not(self) -> Self::Output {
        Permissions(!self.0)
    }
}

fn main() {
    let rw = Permissions::READ | Permissions::WRITE;
    println!("Read | Write: {:?}", rw);
    println!("Has Read: {}", rw.contains(Permissions::READ));
    println!("Complement: {:?}", !rw);
}

steps.code:
const READ: Permissions = Permissions(1);
const WRITE: Permissions = Permissions(2);
const EXECUTE: Permissions = Permissions(4);

fn bitor(self, rhs: Self) -> Self::Output {
    Permissions(self.0 | rhs.0)
}

fn contains(&self, other: Permissions) -> bool {
    (self.0 & other.0) == other.0
}

